    ) RETURNING id INTO v_ept_id;

    FOR i IN 1..8 LOOP
      INSERT INTO public.predictions (
        event_id, event_prediction_type_id, user_id, prediction_type,
        prediction_data, is_correct, is_partial, points_awarded,
        submitted_at, updated_at
      ) VALUES (
